### **Optimization 4: INA226 Calibration Register**
```cpp
void initINA226Battery() {
  ina226.begin();

  // Set calibration for 20A max (improves accuracy)
  // Calibration = 0.04096 / (Max Current * Shunt Resistor)
  // For 20A @ 0.01Ω: calibration = 0.04096 / (20 * 0.01) = 204.8 → 0xCCC
  Wire.beginTransmission(INA226_ADDR);
  Wire.write(0x05);  // Calibration register
  Wire.write(0x0C);
  Wire.write(0xCC);
  Wire.endTransmission();

  state.ina226Aktiv = true;
}
```

