      Serial.println("! AHT20 initialization failed");
      allOk = false;
    }

    // Initialize BMP280
    if (!bmp280.begin()) {
      Serial.println("! BMP280 initialization failed");
      allOk = false;
    } else {
      bmp280.setSampling(Adafruit_BMP280::MODE_FORCED,
                         Adafruit_BMP280::SAMPLING_X2,
                         Adafruit_BMP280::SAMPLING_X16,
