// WAKE REASON HANDLING
// ============================================================
void handleWakeReason(rst_info* resetInfo) {
  bool funkSignalActive = (resetInfo->reason == REASON_EXT_SYS_RST) && 
                          (digitalRead(FUNK_PIN) == LOW);

  if (funkSignalActive) {
    handleFunkSignal();
  } else {
    handleTimerWake();
