  bool initialize() {
    ESP.rtcUserMemoryRead(0, (uint32_t*)&rtcData, sizeof(rtcData));
    rtcValid = validateRTC();  // Check CRC!

    if (!rtcValid) {
      resetRTC();  // Start fresh
    }
    return rtcValid;
  }

  bool validateRTC() {
    uint32_t calculated = calculateCRC32(...);
    if (calculated != rtcData.crc32) {
