  uint32_t heizungStartZeit;         // 4 bytes
  uint32_t letzteDisplayAktualisierung;
  uint32_t startTick;                // 4 bytes
  uint32_t gesamtEnergie_Wh_x100;    // Store as int (saves 4 bytes vs float)

